mapper.select:
SELECT r.*, p.patient_name, p.patient_no, p.gender, p.age, p.id_card, p.phone,
       d.dept_name, u.real_name as doctor_name
FROM registration r
LEFT JOIN patient p ON r.patient_id = p.patient_id
LEFT JOIN department d ON r.dept_id = d.dept_id
LEFT JOIN sys_user u ON r.doctor_id = u.user_id

    AND r.patient_id = #{patientId}
    AND r.doctor_id = #{doctorId}
    AND r.status = #{status}

ORDER BY r.create_time DESC

mapper.update:
UPDATE registration
status = #{status}, queue_number = #{queueNumber},
WHERE reg_id = #{regId}
